UPDATE 
    organization_role
SET
    del_yn = CASE



                    WHEN organization_id = #{organizationRole.organizationId}
                    AND role_id = #{organizationRole.roleId}
                    THEN #{organizationRole.delYn}


                    WHEN organization_id = #{organizationRole.organizationId}
                    AND role_id = #{organizationRole.roleId}
                    THEN del_yn



        ELSE del_yn
    END,
    chg_id = CASE 



                    WHEN organization_id = #{organizationRole.organizationId}
                    AND role_id = #{organizationRole.roleId}
                    THEN #{organizationRole.chgId}


                    WHEN organization_id = #{organizationRole.organizationId}
                    AND role_id = #{organizationRole.roleId}
                    THEN chg_id



        ELSE chg_id
    END,
    chg_dt = CASE 



                    WHEN organization_id = #{organizationRole.organizationId}
                    AND role_id = #{organizationRole.roleId}
                    THEN #{organizationRole.chgDt}


                    WHEN organization_id = #{organizationRole.organizationId}
                    AND role_id = #{organizationRole.roleId}
                    THEN chg_dt



        ELSE chg_dt
    END,
    del_id = 



                    WHEN organization_id = #{organizationRole.organizationId} AND role_id = #{organizationRole.roleId} THEN NULL::uuid


                    WHEN organization_id = #{organizationRole.organizationId} AND role_id = #{organizationRole.roleId} THEN #{organizationRole.delId}


                    WHEN organization_id = #{organizationRole.organizationId} AND role_id = #{organizationRole.roleId} THEN del_id


        ,
    del_dt = 



                    WHEN organization_id = #{organizationRole.organizationId} AND role_id = #{organizationRole.roleId} THEN NULL::timestamp


                    WHEN organization_id = #{organizationRole.organizationId} AND role_id = #{organizationRole.roleId} THEN #{organizationRole.delDt}


                    WHEN organization_id = #{organizationRole.organizationId} AND role_id = #{organizationRole.roleId} THEN del_dt



WHERE (organization_id, role_id) IN (

        (#{organizationRole.organizationId},
         #{organizationRole.roleId})

)

mapper.select:
SELECT ors.organization_id, ors.role_id, o.organization_name, r.role_name, ors.reg_id, ors.reg_dt, ors.chg_id, ors.chg_dt, ors.del_id, ors.del_dt, ors.del_yn FROM organization_role ors INNER JOIN organization o ON ors.organization_id = o.organization_id INNER JOIN role r ON ors.role_id = r.role_id
AND ors.organization_id IN #{organizationId}
AND ors.role_id IN #{roleId}
AND o.organization_name ILIKE '%' || #{filter.organizationName} || '%'
AND r.role_name ILIKE '%' || #{filter.roleName} || '%'
AND ors.del_yn = #{filter.delYn}
